for (const item of $input.all()) {
  const fechaBase = new Date(item.json.fecha);

  const año = fechaBase.getFullYear();
  const mes = fechaBase.getMonth(); // Recuerda: enero = 0
  const dia = fechaBase.getDate();

  // Crear fecha de inicio (08:00:00)
  const fechaInicio = new Date(año, mes, dia, 8, 0, 0);

  // Crear fecha de fin (18:00:00)
  const fechaFin = new Date(año, mes, dia, 18, 0, 0);

  // Función para formatear sin la "Z"
  const formatear = (date) => {
    const pad = (n) => n.toString().padStart(2, '0');
    return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`;
  };

  item.json.fechaInicio = formatear(fechaInicio);
  item.json.fechaFin = formatear(fechaFin);
}

return $input.all();

const salida = [];

for (const item of $input.all()) {
  const dateTimeString = item.json.start.dateTime;

  // Extraer solo la hora en texto sin conversión de zona horaria
  const horaFormateada = dateTimeString.split("T")[1].substring(0,5); // Ej: "11:00"

  salida.push(horaFormateada);
}

// Ordenar alfabéticamente (funciona bien con formato HH:mm)
salida.sort();

return [
  {
    json: {
      horasOcupadas: salida
    }
  }
];

// Horas ocupadas que vienen del input
const horasOcupadas = $input.first().json.horasOcupadas;

// Convertir a Set para búsquedas rápidas
const ocupadasSet = new Set(horasOcupadas);

// Definir rango de atención
const horaInicio = 8;
const horaFin = 18;

// Excluir bloque de almuerzo: 12:00 a 13:59
const esAlmuerzo = (hora) => hora >= 12 && hora < 14;

// Generar todas las horas válidas dentro del rango
const horasDisponibles = [];

for (let hora = horaInicio; hora < horaFin; hora++) {
  if (esAlmuerzo(hora)) continue;

  const horaStr = hora.toString().padStart(2, '0') + ':00';

  if (!ocupadasSet.has(horaStr)) {
    horasDisponibles.push(horaStr);
  }
}

return [
  {
    json: {
      horasDisponibles
    }
  }
];

